It is possible to insert documents that have properties with value 'undefined'; but querying them does not work; 'undefined' appears to be changed to null and querying for 'undefined' returns the properties with value null also.

This code shows the situation, which I think is a bug.

var Db = require('mongodb').Db,
    Server = require('mongodb').Server,
    ObjectID = require('mongodb').ObjectID,
    Binary = require('mongodb').Binary,
    GridStore = require('mongodb').GridStore,
    Code = require('mongodb').Code,
    BSON = require('mongodb').pure().BSON,
    assert = require('assert');

var db = new Db('jiras', new Server("127.0.0.1", 27017,
    {auto_reconnect: false, poolSize: 4}), {w: 0, native_parser: false});

db.open(function (err, db) {
    db.dropCollection("undefined", function (err, result) {

        db.createCollection('undefined', function (err, collection) {
            var undefinedDocument = {"x": undefined, "comment": "undefined"};
            var nullDocument = {"x": null, "comment": "null"};
            console.log("original document:");
            console.log(undefinedDocument);
            console.log(nullDocument);

            collection.insert([undefinedDocument, nullDocument], {w: 1}, function (err, result) {
                var undefinedQuery = {"x": undefined};
                var cursor;
                var cursorStream;

                cursor = collection.find(undefinedQuery);
                cursorStream = cursor.stream();
                cursorStream.on("data", function (docs) {
                    console.log("query:");
                    console.log(undefinedQuery);
                    console.log("result document:");
                    console.log(docs);
                });
                cursorStream.on("close", function () {
                    db.close();
                });
            });
        });
    });
});

When inserting a document with a property of value Timestamp() and this is queried, then this works fine.

However, if the dataset contains a second document with a property of Date(), completely unrelated to the first document, and a query for Timestamp() is issued, the driver errors out.

The following code shows the error case. If you comment out the document with the Date() property, the query works on the single document.

var Db = require('mongodb').Db,
    Server = require('mongodb').Server,
    ObjectID = require('mongodb').ObjectID,
    Binary = require('mongodb').Binary,
    GridStore = require('mongodb').GridStore,
    Code = require('mongodb').Code,
    BSON = require('mongodb').pure().BSON,
    assert = require('assert'),
    MongoDB = require('mongodb');

var db = new Db('jiras', new Server("127.0.0.1", 27017,
    {auto_reconnect: false, poolSize: 4}), {w: 0, native_parser: false});

db.open(function (err, db) {
    db.dropCollection("timestamp", function (err, result) {

        db.createCollection('timestamp', function (err, collection) {
            if (err) {
                console.log(err);
            }
            var timestampDocument = {"x": new MongoDB.Timestamp(1, 2), "comment": "Timestamp(1,2)"};
            var dateDocument = {"x": new Date("2012-08-31 12:13:14:156 UTC"), "comment": "2012-08-31 12:13:14:156 UTC"};
            console.log("original document:");
            console.log(timestampDocument);
            console.log(dateDocument);

            collection.insert([timestampDocument, dateDocument], {w: 1}, function (err, result) {
                var timestampQuery = {"x": new MongoDB.Timestamp(1, 2)};
                var cursor;
                var cursorStream;

                assert.equal(null, err);

                cursor = collection.find(timestampQuery);
                cursorStream = cursor.stream();
                cursorStream.on("data", function (docs) {
                    console.log("query:");
                    console.log(timestampQuery);
                    console.log("result document:");
                    console.log(docs);
                });
                cursorStream.on("close", function () {
                    db.close();
                });
                cursorStream.on("error", function (err) {
                    console.log(err);
                });
            });
        });
    });
});

When creating properties with value of Code() (plus context), querying documents with this properties does not return correct result.

The following code inserts a document, but when querying it with a non-matching query, it is returned (see the context: the context in the query is different from the context in the document, and it is still being returned).

var Db = require('mongodb').Db,
    Server = require('mongodb').Server,
    ObjectID = require('mongodb').ObjectID,
    Binary = require('mongodb').Binary,
    GridStore = require('mongodb').GridStore,
    Code = require('mongodb').Code,
    BSON = require('mongodb').pure().BSON,
    assert = require('assert');

var db = new Db('jiras', new Server("127.0.0.1", 27017,
    {auto_reconnect: false, poolSize: 4}), {w: 0, native_parser: false});

db.open(function (err, db) {
    db.dropCollection("code", function (err, result) {

        db.createCollection('code', function (err, collection) {
            if (err) {
                console.log(err);
            }
            var codeDocument = {"x": new Code("function () {}", {a: 55}), "comment": "Code w/scope a:55"};
            console.log("original document:");
            console.log(codeDocument);

            collection.insert(codeDocument, {w: 1}, function (err, result) {
                var codeQuery = {"x": new Code("function () {}", {b: 77})};
                var cursor;
                var cursorStream;

                assert.equal(null, err);

                cursor = collection.find(codeQuery);
                cursorStream = cursor.stream();
                cursorStream.on("data", function (docs) {
                    console.log("query:");
                    console.log(codeQuery);
                    console.log("result document:");
                    console.log(docs);
                });
                cursorStream.on("close", function () {
                    db.close();
                });
            });
        });
    });
});
